SELECT ORDERH.CUSTCODE, ORDERH.REF, ORDERI.PRODUCT, ORDERI.DESC1, ORDERI.DESC2, ORDERH.OHINVREF, ORDERI.QUANTITY, ORDERI.COST, ORDERI.TOTNET, ORDERH.OHSPLPRICEPOINT, ORDERH.QTRESULTORDERREF, ORDERH.CRNOTE, CUSTOMER.SICCODE, CASE WHEN ORDERH.CRNOTE = TRUE THEN ORDERI.TOTNET * -1 ELSE ORDERI.TOTNET END AS TOTAL_REVENUE, CASE WHEN ORDERH.CRNOTE = TRUE THEN ORDERI.COST * -1 ELSE ORDERI.COST END AS NEW_COST FROM ORDERH LEFT OUTER JOIN ORDERI ON ORDERH.REF = ORDERI.REF LEFT OUTER JOIN CUSTOMER ON ORDERH.CUSTCODE = CUSTOMER.CODE WHERE ORDERH.OHINVDATE > {d '2024-01-01'} AND ORDERI.DESC2 LIKE '%PROMOTION%' AND ORDERH.INSTATUS = 1
